package com.yottastudios.ns.collabspace.announcement.ro;

import io.swagger.v3.oas.annotations.media.Schema;
import jakarta.validation.constraints.NotNull;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.time.LocalDateTime;

@Data
@NoArgsConstructor
@AllArgsConstructor
@Builder
@Schema(name = "CreateAnnouncementRo")
public class CreateAnnouncementRo {

    @Schema(description = "公告标题", example = "xxx", requiredMode = Schema.RequiredMode.REQUIRED)
    private String title;

    @Schema(description = "公告内容", example = "xxx", requiredMode = Schema.RequiredMode.REQUIRED)
    private String content;

    @Schema(description = "是否弹窗", example = "true/false", requiredMode = Schema.RequiredMode.REQUIRED)
    private Boolean isPopup;

    @Schema(description = "发布日期", example = "yyyy-MM-dd HH:mm:ss", requiredMode = Schema.RequiredMode.REQUIRED)
    private String publishTime;

    @Schema(description = "公告id", example = "111111", requiredMode = Schema.RequiredMode.NOT_REQUIRED)
    private Long announcementId;

    private String spaceId;

    @Schema(description = "公告类别：0-空间站公告 1-平台公告，不传默认平台公告", example = "1")
    private Integer announcementCategory;

    private String expireTime;
}

