 1→import { announceTo, toAnnounce } from '@/common/dataConversion/announce.ts';
 2→import type { IAnnouncementItem } from '@/types/announcement.ts';
 3→import { objectOmit } from '@/utils/object.ts';
 4→import { fetchData } from '@/utils/request.ts';
 5→
 6→export const createAnnounce = (v: IAnnouncementItem) => {
 7→  return fetchData({
 8→    url: '/api/v1/announcement/create',
 9→    method: 'POST',
10→    data: objectOmit(announceTo(v), ['announcementId']),
11→  });
12→};
13→export const updateAnnounce = (v: IAnnouncementItem) => {
14→  return fetchData({
15→    url: '/api/v1/announcement/create',
16→    method: 'POST',
17→    data: announceTo(v),
18→  });
19→};
20→// 通告取消发布
21→export const cancelAnnounce = (v: IAnnouncementItem) => {
22→  return fetchData({
23→    url: '/api/v1/announcement/update',
24→    method: 'POST',
25→    data: {
26→      announcementId: v.announceId,
27→      status: 2,
28→    },
29→  });
30→};
31→// 获取正在等待发布的公告
32→export const getWaitingAnnouncement = () => {
33→  return fetchData<void, ({
34→    isPopup: boolean; id: string;
35→  } & IAnnouncementItem) []>({
36→    url: '/api/v1/announcement/list/waiting',
