 84→    @Override
 85→    @Transactional(rollbackFor = Exception.class)
 86→    public CreateAnnouncementVo createAnnouncement(CreateAnnouncementRo ro) {
 87→        log.info("[lbl][2210-公告][Announcement][CREATE] 开始创建/更新公告, category={}, spaceId={}, title={}", ro.getAnnouncementCategory(), ro.getSpaceId(), ro.getTitle());
 88→
 89→        // 0. 兼容旧前端：不传 announcementCategory 时，根据 spaceId 推断类别
 90→        if (ro.getAnnouncementCategory() == null) {
 91→            ro.setAnnouncementCategory(StringUtils.hasText(ro.getSpaceId())
 92→                    ? AnnouncementCategory.SPACE.getCode()
 93→                    : AnnouncementCategory.PLATFORM.getCode());
 94→        }
 95→
 96→        // 1. 空间站公告需校验管理员权限（主管理员 或 文档管理员）
 97→        checkSpaceAnnouncementPermission(ro.getAnnouncementCategory(), ro.getSpaceId());
 98→
 99→        // 2. 校验基本入参
100→        if (!StringUtils.hasText(ro.getTitle())) {
101→            throw new BusinessException("公告标题不能为空");
102→        }
103→        if (!StringUtils.hasText(ro.getContent())) {
104→            throw new BusinessException("公告内容不能为空");
105→        }
106→
107→        LocalDateTime now = LocalDateTime.now();
108→        LocalDateTime publishTime;
109→        if (StringUtils.hasText(ro.getPublishTime())) {
110→            publishTime = LocalDateTime.parse(ro.getPublishTime(), DATE_TIME_FORMATTER);
111→        } else {
112→            // 无发布时间 = 立即发布
113→            publishTime = now;
114→        }
115→
116→        // 判断是否定时：发布时间比当前晚 10 分钟以上才算定时
117→        boolean isTimed = publishTime.isAfter(now.plusMinutes(10));
118→        // 明确传了未来时间（超过1分钟容差）但不足10分钟，拒绝；1分钟内视为"立即发布"兼容时钟偏差
119→        if (!isTimed && StringUtils.hasText(ro.getPublishTime()) && publishTime.isAfter(now.plusMinutes(1))) {
120→            throw new BusinessException("定时发布时间必须晚于当前时间至少 10 分钟");
121→        }
122→
123→        // 校验过期时间
124→        if (StringUtils.hasText(ro.getExpireTime())) {
125→            LocalDateTime expireTime = LocalDateTime.parse(ro.getExpireTime(), DATE_TIME_FORMATTER);
126→            if (!expireTime.isAfter(publishTime)) {
127→                throw new BusinessException("过期时间必须晚于发布时间");
128→            }
129→        }
130→
131→        // 2. 获取当前用户信息
132→        Long userId = SessionContext.getUserId();
133→        UserSimpleInfoVo userInfo = apitableGrpcClientService.getUserById(userId);
134→        String userName = userInfo != null ? userInfo.getNickName() : "";
135→
136→        // 3. 如果是编辑（announcementId != null），将旧公告下线
137→        if (ro.getAnnouncementId() != null) {
138→            AnnouncementEntity old = announcementMapper.selectById(ro.getAnnouncementId());
139→            if (old != null) {
140→                old.setStatus(AnnouncementStatus.OFFLINE.getCode());
141→                old.setOfflineTime(now);
142→                announcementMapper.updateById(old);
143→                pushOfflineNotification(old);
144→                log.info("[lbl][2210-公告][Announcement][UPDATE] 编辑操作将旧公告下线, announcementId={}", old.getId());
145→            }
146→        }
147→
148→        // 4. 检查同类型（spaceId + category）是否有当前生效公告，自动下线
149→        offlineActiveAnnouncementByCategory(ro.getSpaceId(), ro.getAnnouncementCategory(), now);
150→
151→        // 5. 构建新公告实体（始终 INSERT）
152→        AnnouncementEntity entity = new AnnouncementEntity();
153→        entity.setTitle(ro.getTitle());
154→        entity.setContent(ro.getContent());
155→        entity.setIsPopup(ro.getIsPopup() != null ? ro.getIsPopup() : false);
156→        entity.setSpaceId(ro.getSpaceId());
157→        entity.setAnnouncementCategory(ro.getAnnouncementCategory());
158→        entity.setCreatorId(userId);
159→        entity.setCreatorName(userName);
160→        entity.setPublisherId(userId);
161→        entity.setPublisherName(userName);
162→        entity.setPublishTime(publishTime);
163→        if (StringUtils.hasText(ro.getExpireTime())) {
164→            entity.setExpireTime(LocalDateTime.parse(ro.getExpireTime(), DATE_TIME_FORMATTER));
165→        }
166→
167→        String operationMessage;
168→        if (isTimed) {
169→            // 6. 定时发布
170→            entity.setType(AnnouncementType.TIMED.getCode());
171→            entity.setStatus(AnnouncementStatus.TIMED.getCode());
172→            operationMessage = "公告已设置定时发布";
173→        } else {
174→            // 7. 立即发布
175→            entity.setType(AnnouncementType.IMMEDIATE.getCode());
176→            entity.setStatus(AnnouncementStatus.PUBLISHED.getCode());
177→            entity.setPublishTime(now);
178→            operationMessage = "公告已立即发布";
179→        }
180→
181→        // 8. INSERT 新实体
182→        announcementMapper.insert(entity);
183→        log.info("[lbl][2210-公告][Announcement][CREATE] 新公告已创建, announcementId={}, status={}, category={}, spaceId={}", entity.getId(), entity.getStatus(), entity.getAnnouncementCategory(), entity.getSpaceId());
184→
185→        // 9. 事务提交后再发 MQ / WebSocket，避免事务回滚但消息已发出
186→        final boolean finalIsTimed = isTimed;
187→        final String[] opMsgHolder = {operationMessage};
188→        TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
189→            @Override
190→            public void afterCommit() {
191→                if (finalIsTimed) {
192→                    try {
193→                        long delayMillis = Duration.between(LocalDateTime.now(), publishTime).toMillis();
194→                        Message mqMessage = new Message(entity.getId().toString().getBytes());
195→                        rabbitMqSender.sendDelayedMessage(QueueConfig.ANNOUNCEMENT_EXCHANGE, QueueConfig.ANNOUNCEMENT_KEY, mqMessage, delayMillis);
196→                        log.info("[lbl][2210-公告][Announcement][CREATE] 定时发布任务已入队, announcementId={}, delayMs={}", entity.getId(), delayMillis);
197→                    } catch (Exception e) {
198→                        log.error("[lbl][2210-公告][Announcement][CREATE] 定时发布任务入队失败, announcementId={}, error={}", entity.getId(), e.getMessage(), e);
199→                    }
200→                } else {
201→                    pushAnnouncementNotification(entity);
202→                }
203→            }
204→        });
205→
206→        CreateAnnouncementVo result = new CreateAnnouncementVo();
207→        result.setId(entity.getId());
208→        result.setTitle(entity.getTitle());
209→        result.setContent(entity.getContent());
210→        result.setPublishTime(entity.getPublishTime());
211→        result.setMessage(operationMessage);
212→
213→        log.info("[lbl][2210-公告][Announcement][CREATE] 创建/更新完成, announcementId={}, userId={}, message={}", entity.getId(), userId, operationMessage);
214→        return result;
215→    }
