395→        if (announcement == null) {
396→            return false;
397→        }
398→        if (!skipPermissionCheck) {
399→            checkPlatformAnnouncementWritePermission(announcement.getAnnouncementCategory());
400→            checkSpaceAnnouncementPermission(announcement.getAnnouncementCategory(), announcement.getSpaceId());
401→        }
402→        // MyBatis-Plus deleteById 走逻辑删除（@TableLogic）
403→        boolean result = announcementMapper.deleteById(announcementId) > 0;
404→        log.info("[lbl][2210-公告][Announcement][DELETE] 软删除公告, announcementId={}, userId={}, result={}", announcementId, SessionContext.getUserId(), result);
405→        return result;
406→    }
