431→        List<AnnouncementEntity> expiredList = announcementMapper.selectList(new LambdaQueryWrapper<AnnouncementEntity>()
432→                .eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode())
433→                .isNotNull(AnnouncementEntity::getExpireTime)
434→                .lt(AnnouncementEntity::getExpireTime, now));
435→        if (expiredList.isEmpty()) {
436→            return;
437→        }
438→        log.info("[lbl][2210-公告][ExpireTask] 扫描到 {} 条已到期公告，开始自动下线", expiredList.size());
439→        // 批量设置状态，减少逐条 UPDATE
440→        for (AnnouncementEntity entity : expiredList) {
441→            entity.setStatus(AnnouncementStatus.OFFLINE.getCode());
442→            entity.setOfflineTime(now);
443→        }
444→        updateBatchById(expiredList);
445→        // 批量更新后再推送通知
446→        for (AnnouncementEntity entity : expiredList) {
447→            pushOfflineNotification(entity);
448→            log.info("[lbl][2210-公告][ExpireTask] 到期自动下线, announcementId={}, expireTime={}", entity.getId(), entity.getExpireTime());
449→        }
