452→    @Override
453→    @Transactional(rollbackFor = Exception.class)
454→    public void publishTimedAnnouncement(Long announcementId) {
455→        AnnouncementEntity announcement = announcementMapper.selectById(announcementId);
456→        // 公告不存在
457→        if (announcement == null) {
458→            log.info("[lbl][2210-公告][Consumer] 公告不存在, announcementId={}", announcementId);
459→            return;
460→        }
461→        // 已取消或为立即发布类型，跳过处理
462→        if (announcement.getStatus() == AnnouncementStatus.CANCELLED.getCode()
463→                || announcement.getType() == AnnouncementType.IMMEDIATE.getCode()) {
464→            log.info("[lbl][2210-公告][Consumer] 公告无需发布, announcementId={}, status={}, type={}",
465→                    announcementId, announcement.getStatus(), announcement.getType());
466→            return;
467→        }
468→
469→        LocalDateTime now = LocalDateTime.now();
470→
471→        // 自动下线同分类下已发布的其他公告
472→        offlineActiveAnnouncementByCategory(announcement.getSpaceId(), announcement.getAnnouncementCategory(), now);
473→
474→        // 更新当前公告状态为已发布
475→        announcement.setStatus(AnnouncementStatus.PUBLISHED.getCode());
476→        announcement.setPublishTime(now);
477→        announcementMapper.updateById(announcement);
478→
479→        // 事务提交后再推送 WebSocket 通知
480→        AnnouncementEntity entityForPush = announcement;
481→        TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
482→            @Override
483→            public void afterCommit() {
484→                pushAnnouncementNotification(entityForPush);
485→            }
486→        });
487→
488→        log.info("[lbl][2210-公告][Consumer] 定时公告发布成功, announcementId={}, spaceId={}, category={}",
489→                announcement.getId(), announcement.getSpaceId(), announcement.getAnnouncementCategory());
490→    }
