502→    @Override
503→    public void syncAnnouncement() {
504→        // 轮询接口：从外网同步公告
505→        List<AnnouncementEntity> exactAnnouncementList = collabspaceGrpcClientService.getExactAnnouncement();
506→        List<Long> announcementIdList = exactAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
507→        List<AnnouncementEntity> interAnnouncementList = CollectionUtil.isEmpty(announcementIdList) ? new ArrayList<>()
508→                : announcementMapper.selectBatchIds(announcementIdList);
509→        List<Long> existedAnnouncementIdList = interAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
510→        List<AnnouncementEntity> updateList = interAnnouncementList.stream()
511→                .filter(o -> announcementIdList.contains(o.getId())).toList();
512→        List<AnnouncementEntity> addList = exactAnnouncementList.stream()
513→                .filter(o -> !existedAnnouncementIdList.contains(o.getId())).toList();
514→
515→        for (AnnouncementEntity addAnnouncement : addList) {
516→            announcementMapper.insert(addAnnouncement);
517→        }
518→        for (AnnouncementEntity updateAnnouncement : updateList) {
519→            announcementMapper.updateById(updateAnnouncement);
520→        }
521→    }
