import { announceTo, toAnnounce } from '@/common/dataConversion/announce.ts';
import type { IAnnouncementItem } from '@/types/announcement.ts';
import { objectOmit } from '@/utils/object.ts';
import { fetchData } from '@/utils/request.ts';

export const createAnnounce = (v: IAnnouncementItem) => {
  return fetchData({
    url: '/api/v1/announcement/create',
    method: 'POST',
    data: objectOmit(announceTo(v), ['announcementId']),
  });
};
export const updateAnnounce = (v: IAnnouncementItem) => {
  return fetchData({
    url: '/api/v1/announcement/create',
    method: 'POST',
    data: announceTo(v),
  });
};
// 通告取消发布
export const cancelAnnounce = (v: IAnnouncementItem) => {
  return fetchData({
    url: '/api/v1/announcement/update',
    method: 'POST',
    data: {
      announcementId: v.announceId,
      status: 2,
    },
  });
};
// 获取正在等待发布的公告
export const getWaitingAnnouncement = () => {
  return fetchData<void, ({
    isPopup: boolean; id: string;
  } & IAnnouncementItem) []>({
    url: '/api/v1/announcement/list/waiting',
    method: 'GET',
  }).then((r) => {
    return r.map(toAnnounce);
  });
};

// 查找最新公告
export const getLatestAnnouncement = () => {
  return fetchData<void, ({
    isPopup: boolean; id: string;
  } & IAnnouncementItem)>({
    url: '/api/v1/announcement/last',
    method: 'GET',
  }).then((r) => {
    return toAnnounce(r);
    // return r.map(toAnnounce);
  });
};
// 查找已发布的公告
export const getPublishedAnnouncement = () => {
  return fetchData<void, ({
    isPopup: boolean; id: string;
  } & IAnnouncementItem)[]>({
    url: '/api/v1/announcement/list/published',
    method: 'GET',
  }).then((r) => {
    // return  toAnnounce(r);
    return r.map(toAnnounce);
  });
};
// 获取升级公告红点数据
export const getAnnounceRedDot = () => {
  return fetchData<void, boolean>({
    url: '/api/v1/announcement/redpots',
    method: 'GET',
  });
};

