package com.yottastudios.ns.collabspace.announcement.service;

import com.baomidou.mybatisplus.extension.service.IService;
import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementEntity;
import com.yottastudios.ns.collabspace.announcement.ro.CreateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.RepublishAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.UpdateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.vo.ActiveAnnouncementVo;
import com.yottastudios.ns.collabspace.announcement.vo.CreateAnnouncementVo;
import com.yottastudios.ns.collabspace.announcement.vo.GetListAnnouncementVo;

import java.util.List;


public interface IAnnouncementService extends IService<AnnouncementEntity> {

    CreateAnnouncementVo createAnnouncement(CreateAnnouncementRo ro);

    List<GetListAnnouncementVo> getAnnounceList(int status, String spaceId, Integer announcementCategory);

    Boolean changeAnnouncementStatus(UpdateAnnouncementRo ro);

    /**
     * 管理后台专用：修改公告状态（跳过前台权限校验）
     */
    Boolean changeAnnouncementStatusByAdmin(UpdateAnnouncementRo ro);

    GetListAnnouncementVo getLastAnnouncement();

    void addAnnouncementReadRecord(Long announcementId, String spaceId);

    Boolean judgeRedPots(String spaceId);

    void syncAnnouncement();

    List<GetListAnnouncementVo> getAnnouncementById(List<Long> announcementIdListList);

    List<ActiveAnnouncementVo> getActiveAnnouncements(String spaceId);

    List<GetListAnnouncementVo> getHistoryList(String spaceId, Integer announcementCategory);

    Boolean deleteAnnouncement(Long announcementId);

    /**
     * 管理后台专用：删除公告（跳过前台权限校验）
     */
    Boolean deleteAnnouncementByAdmin(Long announcementId);

    CreateAnnouncementVo republishAnnouncement(RepublishAnnouncementRo ro);

    void offlineExpiredAnnouncements();

    /**
     * 定时公告到期发布：下线同类旧公告 → 发布当前公告 → 推送 WebSocket
     * 由 Consumer 调用，带事务保护
     */
    void publishTimedAnnouncement(Long announcementId);

    /**
     * 管理后台：获取所有平台公告（不限状态，一次查询）
     */
    List<GetListAnnouncementVo> getAllPlatformAnnouncements();
}

