import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;
import java.util.Objects;

@Slf4j
@RestController
@Tag(name = "Announcement")
@ApiResource(path = "/announcement")
public class AnnouncementController {

    @Resource
    private IAnnouncementService announcementService;


    /**
     * 创建公告
     */
    @PostResource(path = "/create", requiredPermission = false)
    @Operation(summary = "Create Announcement")
    public ResponseData<Void> createAnnouncement(@RequestBody @Valid CreateAnnouncementRo ro) {
        // 前台接口仅允许创建空间站公告，平台公告须通过管理后台
        if (Objects.equals(ro.getAnnouncementCategory(), AnnouncementCategory.PLATFORM.getCode())) {
            return ResponseData.error("平台公告请通过管理后台创建");
        }
        announcementService.createAnnouncement(ro);
        return ResponseData.success();
    }

    /**
     * 获取待发布列表
     * @return List<GetListAnnouncementVo>
     */
    @GetResource(path = "/list/waiting", requiredPermission = false)
    @Operation(summary = "list waiting")
    public ResponseData<List<GetListAnnouncementVo>> getWaitingAnnouncement(
            @RequestParam(required = false) String spaceId,
            @RequestParam(required = false) Integer announcementCategory) {
        List<GetListAnnouncementVo> voList = announcementService.getAnnounceList(
                AnnouncementStatus.WAITING.getCode(), spaceId, announcementCategory);
        return ResponseData.success(voList);
    }

    /**
     * 获取发布列表（已移除自动标记已读，请通过 /announcement/read 显式标记）
     * @return List<GetListAnnouncementVo>
     */
    @GetResource(path = "/list/published", requiredPermission = false)
    @Operation(summary = "list published")
    public ResponseData<List<GetListAnnouncementVo>> getPublishedAnnouncement(
            @RequestParam(required = false) String spaceId,
            @RequestParam(required = false) Integer announcementCategory) {
        List<GetListAnnouncementVo> voList = announcementService.getAnnounceList(
                AnnouncementStatus.PUBLISHED.getCode(), spaceId, announcementCategory);
        return ResponseData.success(voList);
    }

    /**
     * 修改公告状态
     */
    @PostResource(path = "/update", requiredPermission = false)
    @Operation(summary = "update status or type")
    public ResponseData<Void> changeAnnouncementStatus(@RequestBody @Valid UpdateAnnouncementRo ro) {
        Boolean success = announcementService.changeAnnouncementStatus(ro);
        return success ? ResponseData.success() : ResponseData.error();
    }

    /**
     * 获取最新公告
     * @return GetListAnnouncementVo
     */
    @GetResource(path = "/last", requiredPermission = false)
    @Operation(summary = "get last one")
    public ResponseData<GetListAnnouncementVo> getLastAnnouncement() {
        GetListAnnouncementVo vo = announcementService.getLastAnnouncement();
        return ResponseData.success(vo);
    }


    @GetResource(path = "/redpots", requiredPermission = false)
    @Operation(summary = "red pots view")
    public ResponseData<Boolean> judgeRedPots(@RequestParam(required = false) String spaceId) {
        return ResponseData.success(announcementService.judgeRedPots(spaceId));
    }

    /**
     * 获取历史公告列表
     */
    @GetResource(path = "/list/history", requiredPermission = false)
    @Operation(summary = "获取历史公告列表")
    public ResponseData<List<GetListAnnouncementVo>> getHistoryList(
            @RequestParam(required = false) String spaceId,
            @RequestParam(required = false) Integer announcementCategory) {
        return ResponseData.success(announcementService.getHistoryList(spaceId, announcementCategory));
    }

    /**
     * 软删除公告
     */
    @PostResource(path = "/delete", requiredPermission = false)
    @Operation(summary = "软删除公告")
    public ResponseData<Boolean> deleteAnnouncement(@RequestBody @Valid DeleteAnnouncementRo ro) {
        return ResponseData.success(announcementService.deleteAnnouncement(ro.getAnnouncementId()));
    }

    /**
     * 基于历史公告重新发布
     */
    @PostResource(path = "/republish", requiredPermission = false)
    @Operation(summary = "基于历史公告重新发布")
    public ResponseData<CreateAnnouncementVo> republishAnnouncement(@RequestBody @Valid RepublishAnnouncementRo ro) {
        return ResponseData.success(announcementService.republishAnnouncement(ro));
    }

    /**
     * 获取当前生效公告（空间站+平台，最多2条）
     */
    @GetResource(path = "/active", requiredPermission = false)
    @Operation(summary = "获取当前生效公告（空间站+平台，最多2条）")
    public ResponseData<List<ActiveAnnouncementVo>> getActiveAnnouncements(
            @RequestParam(required = false) String spaceId) {
        return ResponseData.success(announcementService.getActiveAnnouncements(spaceId));
    }

    /**
     * 标记公告已读（显式调用）
     */
    @PostResource(path = "/read", requiredPermission = false)
    @Operation(summary = "标记公告已读")
    public ResponseData<Void> markAnnouncementRead(
            @RequestParam Long announcementId,
            @RequestParam(required = false) String spaceId) {
        announcementService.addAnnouncementReadRecord(announcementId, spaceId);
        return ResponseData.success(null);
    }

}

